def solve(gender, weight_kg, height_cm, age_years):
    # Step 1: calculate_bmr
    # Calculate BMR using Mifflin-St Jeor formula based on gender.
    if gender == 'male':
        bmr = 10 * weight_kg + 6.25 * height_cm - 5 * age_years + 5
    elif gender == 'female':
        bmr = 10 * weight_kg + 6.25 * height_cm - 5 * age_years - 161
    else:
        raise ValueError("Gender must be 'male' or 'female'")
    bmr = round(bmr)

    yield {
        "step_name": "calculate_bmr",
        "step_description": "Calculate BMR using Mifflin-St Jeor formula based on gender.",
        "step_result": float(bmr),
        "unit": "kcal/day"
    }

    return float(bmr)
